#include <iostream>
#include <sstream>
#include <vector>
#include <map>
#include <string>
#include <regex>

int main() {
    // Step 1: Define the input list
    std::string input = "eb1-g1_1, eb2-g1_1, eb3-g2_1, tb1-g2_1, tb2-g3_1, tb3-g3_1, tb4-g3_2, tb5-g1_1, tb6-g2_2";

    // Step 2: Split the input by commas
    std::stringstream ss(input);
    std::string item;

    // Step 3: Create a map to hold results by g_i parameters
    std::map<std::string, std::vector<std::string>> gMap;

    // Step 4: Regex pattern for finding g_i parameters
    std::regex gPattern("g(\\d+)");

    // Step 5: Iterate through the split elements
    while (std::getline(ss, item, ',')) {
        // Trim whitespace
        item.erase(0, item.find_first_not_of(" "));
        item.erase(item.find_last_not_of(" ") + 1);

        std::smatch match;
        // If a g_i pattern is found
        if (std::regex_search(item, match, gPattern)) {
            std::string gParam = match.str(0); // Get matched g_i

            // Add the item to the corresponding vector in the map
            gMap[gParam].push_back(item);
        }
    }

    // Step 6: Output the results
    for (const auto& pair : gMap) {
        std::cout << pair.first << " Parameters: ";
        for (const auto& str : pair.second) {
            std::cout << str << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
```

